 18→async function cleanOrphanedRecords(
 19→	trx: Knex.Transaction,
 20→	childTable: string,
 21→	parentTable: string,
 22→	foreignKeyColumn: string,
 23→	parentKeyColumn: string,
 24→): Promise<void> {
 25→	const orphanedCount = await trx.raw(
 26→		`
 27→		SELECT COUNT(*) as count
 28→		FROM ${childTable} c
 29→		LEFT JOIN ${parentTable} p ON c.${foreignKeyColumn} = p.${parentKeyColumn}
 30→		WHERE p.${parentKeyColumn} IS NULL
 31→	`,
 32→	);
 33→
 34→	const count = orphanedCount[0][0].count as number;
 35→
 36→	logger.log(`Checking ${childTable}: Found ${count} orphaned records`);
 37→
 38→	if (count > 0) {
 39→		logger.warn(
 40→			`Found ${count} orphaned records in ${childTable}. Hard deleting them before adding FK.`,
 41→		);
 42→
 43→		const deleteResult = await trx.raw(
 44→			`
 45→			DELETE c FROM ${childTable} c
 46→			LEFT JOIN ${parentTable} p ON c.${foreignKeyColumn} = p.${parentKeyColumn}
 47→			WHERE p.${parentKeyColumn} IS NULL
 48→		`,
 49→		);
 50→
 51→		logger.log(`Hard deleted ${deleteResult[0].affectedRows} records from ${childTable}`);
 52→
 53→		const verifyCount = await trx.raw(
 54→			`
 55→			SELECT COUNT(*) as count
 56→			FROM ${childTable} c
 57→			LEFT JOIN ${parentTable} p ON c.${foreignKeyColumn} = p.${parentKeyColumn}
 58→			WHERE p.${parentKeyColumn} IS NULL
 59→		`,
 60→		);
 61→
 62→		const remainingCount = verifyCount[0][0].count as number;
 63→		logger.log(
 64→			`After cleanup, ${remainingCount} orphaned records remain in ${childTable}`,
 65→		);
 66→
 67→		if (remainingCount > 0) {
 68→			logger.error(
 69→				`CRITICAL: Failed to clean up all orphaned records in ${childTable}. ${remainingCount} records still orphaned. FK will fail!`,
 70→			);
 71→			throw new Error(
 72→				`Cannot add FK: ${remainingCount} orphaned records remain in ${childTable}`,
 73→			);
 74→		}
 75→	}
 76→}
