import { Logger } from '@nestjs/common';

import {
	TABLE_NAME_COMPANIES,
	TABLE_NAME_COMPANY_MEMBERS,
	TABLE_NAME_USERS,
} from '@constants/db.constant';

import type { Knex } from 'knex';

const logger = new Logger('20260322120002_create_company_members_table.ts');

export async function up(knex: Knex): Promise<void> {
	logger.log('Creating company_members table');

	await knex.transaction(async (trx) => {
		const tableExists = await trx.schema.hasTable(TABLE_NAME_COMPANY_MEMBERS);

		if (!tableExists) {
			await trx.schema.createTable(TABLE_NAME_COMPANY_MEMBERS, (table) => {
				table.uuid('_id').primary().notNullable();
				table
					.uuid('user_id')
					.notNullable()
					.references('_id')
					.inTable(TABLE_NAME_USERS)
					.onDelete('CASCADE');
				table
					.uuid('company_id')
					.notNullable()
					.references('_id')
					.inTable(TABLE_NAME_COMPANIES)
					.onDelete('CASCADE');
				table
					.string('role', 20)
					.notNullable()
					.checkIn(['admin', 'member'], 'chk_company_members_role');
				table
					.timestamp('created_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();
				table
					.timestamp('updated_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();
				table.timestamp('deleted_at', { useTz: true }).nullable();
			});

			await trx.raw(
				`CREATE UNIQUE INDEX idx_company_members_user_company ON ${TABLE_NAME_COMPANY_MEMBERS}(user_id, company_id) WHERE deleted_at IS NULL`,
			);

			await trx.raw(
				`CREATE UNIQUE INDEX idx_one_admin_per_company ON ${TABLE_NAME_COMPANY_MEMBERS}(company_id) WHERE role = 'admin' AND deleted_at IS NULL`,
			);

			logger.log('Successfully created company_members table');
		} else {
			logger.log('company_members table already exists, skipping');
		}
	});
}

export async function down(knex: Knex): Promise<void> {
	logger.log('Dropping company_members table');

	await knex.transaction(async (trx) => {
		await trx.raw(
			`DROP INDEX IF EXISTS idx_company_members_user_company ON ${TABLE_NAME_COMPANY_MEMBERS}`,
		);
		await trx.raw(
			`DROP INDEX IF EXISTS idx_one_admin_per_company ON ${TABLE_NAME_COMPANY_MEMBERS}`,
		);
		await trx.schema.dropTableIfExists(TABLE_NAME_COMPANY_MEMBERS);
	});
